package main

import "fmt"

func main() {
    var s []int

    // Append
    for i := 0; i < 5; i++ {
        s = append(s, i*10)
        fmt.Printf("len=%d cap=%d %v\n", len(s), cap(s), s)
    }

    // Copy
    src := []int{100, 200, 300}
    dst := make([]int, len(src))
    n := copy(dst, src)
    fmt.Println("copied:", n, "dst:", dst)

    // Append slice
    a := []int{1, 2, 3}
    b := []int{4, 5}
    a = append(a, b...)
    fmt.Println("appended:", a)
}
